    if(nums.size() == 1) return 0;
    if(nums[0] > nums[1]) return 0;
    int len = nums.size() - 1;
    if(nums[len] > nums[len - 1]) return len;

    int left = 0, right = len, mid = (left + right) >> 1;

    while(left <= right) {
        if(nums[mid] > nums[mid - 1] && nums[mid] > nums[mid + 1]) {
            return mid;
        } else if(nums[mid] > nums[mid - 1]) {
            left = mid;
        } else if(nums[mid] > nums[mid + 1]) {
            right = mid;
        } else {
            left = mid + 1;
        }

        mid = (left + right) >> 1;
    }

    return -1;
}
```

