bool binary_search(std::vector<int> arr, int target){
    std::sort(arr.begin(), arr.end());

    int left = 0, right = arr.size() - 1, mid = (left + right) >> 1;

    while(left <= right) {
        if(arr[mid] == target) {
            return true;
        } else if(arr[mid] > target) {
