void push(int val) {
    arr[r++] = val;
}

int pop(void) {
    return arr[l++];
}

bool is_empty(void) {
    return l == r;
}

int get_len(void) {
    return r - l;
}
```

循环队列的实现：

```c++
int l = 0, r = 0;
int size = 100;
vector<int> arr(size);

void push(int val) {
    if((r + 1) % size == l)
        return;

    arr[r] = val;
    r = (r + 1) % size;
}

int pop(void) {
    if(l == r)
        return numeric_limits<int>::min();

    int val = arr[l];
    l = (l + 1) % size;

    return val;
}

bool is_empty(void) {
    return l == r;
}

int get_len(void) {
    return (r - l + size) % size;
}
```

