// 先序遍历
void pre_order(node* root) {
    if(!root)
        return;
    printf("%d ", root->val);

    pre_order(root->left);
    pre_order(root->right);
}

// 中序遍历
void in_order(node* root) {
    if(!root)
        return;

    in_order(root->left);

    printf("%d ", root->val);

    in_order(root->right);
}

// 后序遍历
