// 先序遍历
void pre_order_iter(node* root) {
    if(!root) return;

    stack<node*> st;
    st.push(root);

    node* cur = nullptr;

    while(!st.empty()) {
        cur = st.top();
        st.pop();

        cout << cur->val << ' ';

        if(cur->right)
            st.push(cur->right);

        if(cur->left)
            st.push(cur->left);
    }
}

// 中序遍历
void in_order_iter(node* root) {
    if(!root) return;

    stack<node*> st;
    node* cur = root;

    while (cur != nullptr || !st.empty()) {
        while (cur != nullptr) {
            st.push(cur);
            cur = cur->left;
        }

        cur = st.top();
        st.pop();
        cout << cur->val << ' ';

        cur = cur->right;
    }
}

// 后序遍历
void pos_order_iter(node* root) {
    if(!root) return;

    stack<node*> st;
    st.push(root);

    stack<node*> collect;

    node* cur = nullptr;
    while(!st.empty()) {
        cur = st.top();
        st.pop();

        collect.push(cur);

        if(cur->left)
           st.push(cur->left);

        if(cur->right)
            st.push(cur->right);
    }

    while(!collect.empty()) {
        cur = collect.top();
        collect.pop();

        cout << cur->val << ' ';
    }
}
